import sys
from math import inf

def solve():
    data = sys.stdin.read().split()
    n, m = int(data[0]), int(data[1])
    a = data[2]
    b = data[3]

    W = n - m + 1

    # cost to make window i match b
    cost_match = []
    for i in range(W):
        c = sum(1 for j in range(m) if a[i+j] != b[j])
        cost_match.append(c)

    # Check if b has period d (b[j] == b[j+d] for all valid j)
    def has_period(d):
        for j in range(m - d):
            if b[j] != b[j+d]:
                return False
        return True

    # If two match windows at positions p and i (p < i, i < p+m), overlap by (p+m-i) chars
    # They're consistent iff b has period (i-p)
    # Cost to set window i given window p is already set: only need to fix chars p+m..i+m-1
    def overlap_cost(p, i):
        # i > p, i < p+m
        d = i - p
        if not has_period(d):
            return inf  # infeasible
        # chars p..p+m-1 already fixed to b[0..m-1]
        # need chars i+m-d..i+m-1 = p+m..i+m-1 to match b[m-d..m-1]
        extra_cost = 0
        for j in range(m - d, m):
            pos = p + j  # = i + j - d
            if a[pos] != b[j]:
                extra_cost += 1
        return extra_cost

    # For a gap between last match at p (or -1) and next match at i,
    # windows in between (p+1..i-1) must NOT match b.
    # Characters in p..p+m-1 are fixed to b (if p>=0), chars i..i+m-1 fixed to b.
    # For window q in (p+1..i-1), we need it to not match.
    # We can freely set chars not covered by p or i windows.
    # Min cost to break window q: find cheapest char to change that isn't in p's or i's fixed range
    # Actually since we want ALL windows p+1..i-1 to not match, and we can set free chars freely,
    # we set free chars to whatever breaks each window cheaply.
    # But interactions between non-match windows complicate things.
    # Simplification: for each non-match window q, if it's not already broken by fixed chars,
    # we need to change one char. We pick the cheapest free char in that window.
    # We use a greedy: process windows left to right, break each with minimum cost change.

    def gap_cost(p, i):
        # p = last match index (-1 if none), i = next match index (W if none)
        # windows p+1..i-1 must not match
        # fixed chars: [p, p+m) set to b if p>=0; [i, i+m) set to b if i<W
        a_prime = list(a)
        changes = 0
        if p >= 0:
            for j in range(m):
                a_prime[p+j] = b[j]
        if i < W:
            for j in range(m):
                a_prime[i+j] = b[j]
        for q in range(p+1, i):
            # check if window q matches b in a_prime
            matches = all(a_prime[q+j] == b[j] for j in range(m))
            if matches:
                # need to break it - find cheapest free position
                best = inf
                best_pos = -1
                for j in range(m):
                    pos = q + j
                    in_p = (p >= 0 and p <= pos < p+m)
                    in_i = (i < W and i <= pos < i+m)
                    if not in_p and not in_i:
                        if best_pos == -1:
                            best_pos = pos
                if best_pos == -1:
                    return inf  # can't break this window
                a_prime[best_pos] = '1' if a_prime[best_pos] == '0' else '0'
                changes += 1
        return changes

    # Precompute gap costs
    # dp[i][k] = min cost where window i is the k-th match (1-indexed k)
    # Also handle "no more matches after last one"

    INF = float('inf')
    # dp[i][k]: min cost, window i is match number k, windows 0..i processed
    dp = [[INF]*(W+2) for _ in range(W+1)]

    # Initialize: window i is the first match
    for i in range(W):
        gc = gap_cost(-1, i)
        if gc < INF:
            dp[i][1] = cost_match[i] + gc

    # Transitions
    for i in range(W):
        for k in range(1, W+1):
            if dp[i][k] == INF:
                continue
